const staticData = this.getWorkflowStaticData('global');
const totalFilas = items.length;
const script = $json["script"] ?? 'Desconocido';
const timestamp = new Date().toISOString();
const mensaje = `[${timestamp}] Script: ${script} → ${totalFilas} filas`;
if (!staticData.logs) {
  staticData.logs = [];
}
staticData.logs.push(mensaje);
return [{ json: { log: mensaje, acumulado: staticData.logs } }];
